        staleTime: 60 * 60 * 1000, // 1 hour
        cacheTime: 2 * 60 * 60 * 1000, // 2 hours
        refetchOnWindowFocus: false,
        refetchOnMount: false,
        refetchInterval: false,
        retry: 1,
        retryDelay: 1000,
        onError: (error) => {
        }
    });

    return {
        agreements,
        isLoading,
        error,
        refetch
    };
};

