              ${dragActive ? 'bg-zinc-50 shadow-inner' : 'bg-white hover:bg-zinc-50/50'}
              ${disabled ? 'cursor-not-allowed opacity-40 bg-zinc-50' : ''}
              ${isUploading ? 'pointer-events-none' : ''}
              ${error ? 'bg-red-50/30' : ''}
            `} style={{
