const CategoryDistributionChart = ({
  data,
  title = 'Category Distribution'
}) => {
  const {
    t
  } = useTranslation();
  if (!data || Object.keys(data).length === 0) {
    return <div className="flex items-center justify-center h-64">
        <p className="text-slate-400 text-xs font-medium">{t("no_data_available_for_this_period")}</p>
      </div>;
  }
  const labels = Object.keys(data);
  const values = Object.values(data).map(v => parseFloat(v || 0));
  const chartData = {
    labels: labels.map(label => {
      return label.replace(/_/g, ' ').toLowerCase().split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ');
    }),
    datasets: [{
      data: values,
      backgroundColor: CATEGORY_COLORS.slice(0, labels.length),
      borderColor: 'rgba(255,255,255,0.8)',
      borderWidth: 2,
      hoverOffset: 6
    }]
  };
  const options = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'right',
        labels: {
          padding: 16,
          font: {
            size: 11,
            weight: '500'
          },
          color: '#475569',
          usePointStyle: true,
          pointStyleWidth: 8
        }
      },
      title: {
        display: false
      },
      tooltip: {
        backgroundColor: 'rgba(15, 23, 42, 0.9)',
        padding: {
          x: 14,
          y: 10
        },
        titleFont: {
          size: 11,
          weight: '600'
        },
        bodyFont: {
          size: 12,
          weight: '700'
        },
        cornerRadius: 10,
        displayColors: true,
        boxWidth: 8,
        boxHeight: 8,
