            return `${label}: ${value.toLocaleString('tr-TR', {
              minimumFractionDigits: 2,
              maximumFractionDigits: 2
            })} TRY (${percentage}%)`;
          }
        }
      }
    }
  };
  return <div style={{
    height: '300px'
  }}>
      <Pie data={chartData} options={options} />
    </div>;
};
export default CategoryDistributionChart;

