import { useCallback, useMemo, useState } from 'react';
import { useLocation } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { listingService } from '../services/listingService.js';
import { useAuthState } from '../../auth/AuthContext.jsx';
import { useListingFilters } from './useListingFilters.js';
import { useListingPagination } from './useListingPagination.js';
import { useListingSearch } from './useListingSearch.js';
import { LISTING_DEFAULTS, LISTING_TYPES, NON_PURCHASABLE_TYPES } from '../types/index.js';

const LISTING_ENGINE_QUERY_KEYS = {
  listings: ['listings'],
  filtered: (filters) => ['listings', 'filtered', filters],
  mine: (userId, page, size, listingType) => ['listings', 'mine', userId, page, size, listingType || null],
};

/**
 * Orchestrates listing filters, pagination, and search sub-hooks
 */
export const useListingEngine = ({ initialListingType = LISTING_TYPES.VEHICLE, mode: initialMode = 'browse' } = {}) => {
  const location = useLocation();
  const { user, isAuthenticated } = useAuthState();

  const navState = useMemo(() => {
    if (location?.state) return location.state;
    return window.history.state?.usr || null;
  }, [location?.state]);
  const engineModeFromNav = navState?.mode || null;
  const [mode] = useState(engineModeFromNav || initialMode || 'browse');

  // Initialize filters sub-hook (onFiltersChange will be set after search hook initialization)
  const filterHook = useListingFilters({
    initialListingType,
    mode,
    location,
    navState,
    user,
    onFiltersChange: undefined,
  });

  // React Query data fetching
  const queryKey = useMemo(() => {
    if (mode === 'mine') {
      return LISTING_ENGINE_QUERY_KEYS.mine(
        user?.id,
        filterHook.cleanedFilters?.page ?? 0,
        filterHook.cleanedFilters?.size ?? LISTING_DEFAULTS.FILTER_PAGE_SIZE,
        filterHook.cleanedFilters?.listingType || null
      );
    }
    return LISTING_ENGINE_QUERY_KEYS.filtered({ ...filterHook.cleanedFilters, userId: user?.id || null });
  }, [filterHook.cleanedFilters, mode, user?.id]);

  const canFetch = mode === 'mine'
    ? Boolean(isAuthenticated && user?.id)
    : true;

  const { data, isLoading, error: queryError, refetch } = useQuery({
    queryKey,
    queryFn: () => {
      if (mode === 'mine') {
        return listingService.getMyListings(
          filterHook.cleanedFilters?.page ?? 0,
          filterHook.cleanedFilters?.size ?? LISTING_DEFAULTS.FILTER_PAGE_SIZE,
          filterHook.cleanedFilters?.listingType || null
        );
      }
      return listingService.filterListings(filterHook.cleanedFilters);
    },
    enabled: canFetch,
    staleTime: 2 * 60 * 1000,
    gcTime: 5 * 60 * 1000,
    refetchOnWindowFocus: false,
    refetchOnMount: false,
    retry: 2,
    retryDelay: (attemptIndex) => Math.min(1000 * 2 ** attemptIndex, 30000),
  });

  const rawListings = data?.content || [];
  const listings = useMemo(() => {
    if (mode !== 'mine') return rawListings;
    if (!filterHook.mineStatus) return rawListings;
    return rawListings.filter((l) => l?.status === filterHook.mineStatus);
  }, [filterHook.mineStatus, mode, rawListings]);
  const error = queryError?.message || null;

  const paginationHook = useListingPagination({
    data,
    filters: filterHook.filters,
    onPageChange: (page) => filterHook.updateFilters({ page }),
  });

  // Initialize search sub-hook
  const urlSearchQuery = useMemo(() => {
    try {
      return new URLSearchParams(location.search).get('q') || '';
    } catch {
      return '';
    }
  }, [location.search]);

  const searchHook = useListingSearch({
    listings,
    mode,
    filters: filterHook.filters,
    selectedCategory: filterHook.selectedCategory,
    urlSearchQuery,
  });

  // Wire up filter changes to clear search
  const wrappedUpdateFilters = useCallback((newFilters) => {
    filterHook.updateFilters(newFilters);
    searchHook.clearSearch();
  }, [filterHook, searchHook]);

  const wrappedResetFilters = useCallback(() => {
    filterHook.resetFilters();
    searchHook.clearSearch();
  }, [filterHook, searchHook]);

  const wrappedOnCategoryChange = useCallback((category) => {
    filterHook.onCategoryChange(category);
    searchHook.clearSearch();
  }, [filterHook, searchHook]);

  const wrappedSetMineStatus = useCallback((status) => {
    filterHook.setMineStatus(status);
    searchHook.clearSearch();
  }, [filterHook, searchHook]);

  const refresh = useCallback(() => refetch(), [refetch]);

  // Mine-mode specific: low stock alerts
  const lowStockListings = useMemo(() => {
    if (mode !== 'mine') return [];
    const source = searchHook.title.allPagesLoaded ? searchHook.filteredListings : rawListings;
    if (!Array.isArray(source)) return [];
    return source.filter((listing) => {
      if (!listing) return false;
      if (NON_PURCHASABLE_TYPES.includes(listing.type)) return false;
      if (listing.quantity == null) return false;
      const qty = Number(listing.quantity);
      if (!Number.isFinite(qty)) return false;
      return qty > 0 && qty < LISTING_DEFAULTS.LOW_STOCK_MAX_QUANTITY;
    });
  }, [mode, rawListings, searchHook.filteredListings, searchHook.title.allPagesLoaded]);

  const [lowStockOpen, setLowStockOpen] = useState(false);
  const openLowStock = useCallback(() => setLowStockOpen(true), []);
  const closeLowStock = useCallback(() => setLowStockOpen(false), []);
  const toggleLowStock = useCallback(() => setLowStockOpen((v) => !v), []);

  // Return unified interface (backward compatible)
  return {
    mode,
    listings,
    filteredListings: searchHook.filteredListings,
    totalPages: paginationHook.totalPages,
    totalElements: paginationHook.totalElements,
    currentPage: paginationHook.currentPage,
    handlePageChange: paginationHook.handlePageChange,
    isLoading,
    error,
    filters: filterHook.filters,
    selectedCategory: filterHook.selectedCategory,
    updateFilters: wrappedUpdateFilters,
    resetFilters: wrappedResetFilters,
    refresh,
    onCategoryChange: wrappedOnCategoryChange,
    showFilterSidebar: filterHook.showFilterSidebar,
    hasActiveFilters: filterHook.hasActiveFilters,
    toggleFilterSidebar: filterHook.toggleFilterSidebar,
    openFilterSidebar: filterHook.openFilterSidebar,
    closeFilterSidebar: filterHook.closeFilterSidebar,
    search: {
      term: searchHook.searchTerm,
      setTerm: searchHook.setSearchTerm,
      mode: searchHook.searchMode,
      listingNo: searchHook.listingNo,
      title: searchHook.title,
      clear: searchHook.clearSearch,
    },
    mine: mode === 'mine'
      ? {
          status: filterHook.mineStatus,
          setStatus: wrappedSetMineStatus,
        }
      : null,
    alerts: mode === 'mine'
      ? {
          lowStock: {
            isOpen: lowStockOpen,
            open: openLowStock,
            close: closeLowStock,
            toggle: toggleLowStock,
            listings: lowStockListings,
            count: lowStockListings.length,
          },
        }
      : null,
  };
};

import { useTranslation } from "react-i18next";
import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { listingService } from '../services/listingService.js';
import { useAuthState } from '../../auth/AuthContext.jsx';
import { useNotification } from '../../notification/NotificationContext.jsx';
import { listingTypeRegistry, getListingConfig } from '../config/listingConfig.js';
import { ROUTES } from '../../common/constants/routes.js';
import { Loader2, AlertTriangle, ArrowLeft } from 'lucide-react';
import logger from '../../common/utils/logger.js';

// --- Components ---

const PageLoader = () => <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center">
        <Loader2 className="w-10 h-10 text-indigo-600 animate-spin mb-4" />
        <h3 className="text-lg font-medium text-gray-900">{t("loading_listing_details")}</h3>
    </div>;
const PageError = ({
  error,
  onBack
}) => <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="bg-white max-w-md w-full rounded-2xl shadow-xl p-8 text-center">
            <div className="w-16 h-16 bg-red-100 text-red-600 rounded-full flex items-center justify-center mx-auto mb-6">
                <AlertTriangle className="w-8 h-8" />
            </div>
            <h3 className="text-xl font-bold text-gray-900 mb-2">{t("something_went_wrong")}</h3>
            <p className="text-gray-600 mb-8">{error}</p>
            <button onClick={onBack} className="inline-flex items-center gap-2 px-6 py-3 bg-gray-900 text-white rounded-xl hover:bg-black transition-colors font-medium w-full justify-center">
                <ArrowLeft className="w-4 h-4" />{t("go_back_to_listings")}</button>
        </div>
    </div>;
const EditListingPage = ({
  service = null,
  type = null
}) => {
  const {
    t
  } = useTranslation();
  const {
    id
  } = useParams();
  const navigate = useNavigate();
  const {
    user,
    isAuthenticated
  } = useAuthState();
  const notification = useNotification();

  // 1. Fetch Logic
  const [data, setData] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  const fetchingRef = useRef(false);
  const serviceConfig = useMemo(() => {
    if (service) {
      return service;
    }
    if (type) {
      return getListingConfig(type)?.service || null;
    }
    return null;
  }, [type, service]);
  useEffect(() => {
    if (!id || fetchingRef.current) {
      return;
    }
    fetchingRef.current = true;
    const fetchData = async () => {
      setIsLoading(true);
      setError(null);
      try {
        let initialData = null;
        let activeService;
        if (serviceConfig) {
          activeService = serviceConfig;
        } else {
          initialData = await listingService.getListingById(id);
          const currentType = initialData?.type;
          activeService = getListingConfig(currentType)?.service || null;
        }
        if (!activeService?.getById) {
          throw new Error('Editor service not found for this listing type');
        }
        const fullData = await activeService.getById(id);
        setData(fullData);
      } catch (err) {
        logger.error('Failed to fetch listing:', err);
        setError(err.response?.data?.message || err.message || 'Failed to load listing details.');
      } finally {
        setIsLoading(false);
        fetchingRef.current = false;
      }
    };
    fetchData();
    return () => {
      fetchingRef.current = false;
    };
  }, [id, serviceConfig]);

  // 2. Authorization Check
  useEffect(() => {
    if (!isLoading && data && isAuthenticated) {
      const isOwner = user?.id === data?.sellerId;
      if (!isOwner) {
        notification.showError('Access Denied', 'You can only edit your own listings.');
        navigate(ROUTES.MY_LISTINGS, {
          replace: true
        });
      }
    }
  }, [isLoading, data, isAuthenticated, user, navigate, notification]);

  // 3. Update Handler
  const handleUpdate = async updatedFields => {
    try {
      const currentType = type || data?.type;
      const activeService = service || getListingConfig(currentType)?.service || null;
      if (!activeService?.update) {
        throw new Error('Update service not found for this listing type');
      }
      await activeService.update(id, updatedFields);
      notification.showSuccess('Success', 'Listing updated successfully');
      navigate(ROUTES.MY_LISTINGS);
    } catch (err) {
      logger.error('Update failed:', err);
      notification.showError('Update Failed', err.response?.data?.message || err.message || 'Could not update listing');
      throw err;
    }
  };
  if (isLoading) return <PageLoader />;
  if (error) return <PageError error={error} onBack={() => navigate(ROUTES.MY_LISTINGS)} />;
  if (!data) return <PageError error="Listing not found" onBack={() => navigate(ROUTES.MY_LISTINGS)} />;

  // 4. Render Form
  // We render the specific form component directly without a wrapping container
  // The form component (e.g. VehicleCreateForm) handles its own layout via ListingWizard

  const listingType = type || data.type;
  const config = listingTypeRegistry[listingType];
  const EditComponent = config?.editComponent;
  if (!EditComponent) {
    return <PageError error={`No editor available for listing type: ${listingType}`} onBack={() => navigate(ROUTES.MY_LISTINGS)} />;
  }
  return <EditComponent initialData={data} isEdit={true} onUpdate={handleUpdate} onBack={() => navigate(-1)} />;
};
export default EditListingPage;

