const noop = () => {};
const defaultContext = {
    addNotification: noop,
    removeNotification: noop,
    removeAllNotifications: noop,
    showSuccess: noop,
    showError: noop,
    showWarning: noop,
    showInfo: noop,
    showNotification: noop,
    showConfirmation: noop,
